// Parse WhatsApp Cloud API message
try {
  const data = $input.first().json;
  const now = Date.now();

  // Cloud API format
  const entry = data.entry?.[0];
  const change = entry?.changes?.[0];
  const value = change?.value;
  const message = value?.messages?.[0];
  const contact = value?.contacts?.[0];
  const metadata = value?.metadata;

  if (!message) {
    const _out = {
      parseSuccess: false,
      error: true,
      errorType: 'not_a_message',
      errorMessage: 'Not a message event (status update or other)',
      timestamp: new Date().toISOString()
    };
    return [{ json: _out }];
  }

  const phoneNumberId = metadata?.phone_number_id || '';
  const displayPhone = (metadata?.display_phone_number || '').replace(/\D/g, '');
  const from = (message.from || '').replace(/\D/g, '');
  const waId = contact?.wa_id || from;
  const profileName = contact?.profile?.name || '';
  const cloudApiMessageId = message.id || '';
  const msgType = message.type || 'text';

  let body = '';
  let hasMedia = false;
  let mediaUrl = null;
  let mediaType = null;

  if (msgType === 'text') {
    body = message.text?.body || '';
  } else if (['image', 'video', 'audio', 'document'].includes(msgType)) {
    body = message[msgType]?.caption || '';
    hasMedia = true;
    mediaUrl = message[msgType]?.id || null;
    mediaType = message[msgType]?.mime_type || msgType;
  } else if (msgType === 'location') {
    body = `Location: ${message.location?.latitude}, ${message.location?.longitude}`;
  } else if (msgType === 'contacts') {
    body = `Shared contact: ${message.contacts?.[0]?.name?.formatted_name || 'Unknown'}`;
  }

  // Sanitize
  body = (body || '').trim().replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '');
  if (body.length > 2000) body = body.substring(0, 2000);

  if (!phoneNumberId || !from) {
    throw new Error('Missing phoneNumberId or from');
  }

  // Self-message detection: check if sender IS the business number
  // Uses display_phone_number (actual phone number) not phone_number_id (Meta internal ID)
  const isSelfMessage = displayPhone && from === displayPhone;
  let isSelfCommand = false;

  if (isSelfMessage) {
    const upperBody = (body || '').trim().toUpperCase();
    const commandKeywords = ['ONLINE', 'OFFLINE', 'GO ONLINE', 'GO OFFLINE', 'AI ON', 'AI OFF', 'STATUS'];

    if (commandKeywords.includes(upperBody)) {
      // Allow through as agent self-command
      isSelfCommand = true;
    } else {
      // Block non-command self-messages (loop prevention)
      const _out = {
        parseSuccess: false,
        error: true,
        errorType: 'self_message',
        errorMessage: 'Ignoring own message (loop prevention)',
        timestamp: new Date().toISOString()
      };
      return [{ json: _out }];
    }
  }

  // Deduplication: reject recently-seen message IDs
  const staticData = $getWorkflowStaticData('global');
  if (!staticData.recentMsgIds) staticData.recentMsgIds = {};
  const dedupNow = Date.now();
  for (const [mid, ts] of Object.entries(staticData.recentMsgIds)) {
    if (dedupNow - ts > 60000) delete staticData.recentMsgIds[mid];
  }
  if (cloudApiMessageId && staticData.recentMsgIds[cloudApiMessageId]) {
    const _out = {
      parseSuccess: false,
      error: true,
      errorType: 'duplicate',
      errorMessage: 'Duplicate message (already processed)',
      timestamp: new Date().toISOString()
    };
    return [{ json: _out }];
  }
  if (cloudApiMessageId) staticData.recentMsgIds[cloudApiMessageId] = dedupNow;

  const _out = {
    messageId: `msg_${now}`,
    cloudApiMessageId: cloudApiMessageId,
    phoneNumberId: phoneNumberId,
    from: from,
    waId: waId,
    body: body,
    type: msgType,
    isGroup: false,
    isSelfCommand: isSelfCommand,
    hasMedia: hasMedia,
    mediaUrl: mediaUrl,
    mediaType: mediaType,
    profileName: profileName,
    timestamp: new Date().toISOString(),
    processingStartTime: now,
    parseSuccess: true
  };
  return [{ json: _out }];

} catch (error) {
  const _out = {
    parseSuccess: false,
    error: true,
    errorType: 'parse_error',
    errorMessage: error.message,
    timestamp: new Date().toISOString()
  };
  return [{ json: _out }];
}

// Merge message data with agent profile
const message = $('Parse Message').first().json;
const agentRecord = $input.first().json;
const fields = agentRecord.fields || agentRecord;

const agent = {
  recordId: agentRecord.id,
  id: fields.agent_id || agentRecord.id,
  agentName: fields.agent_name || 'Assistant',
  email: fields.email || '',
  companyName: fields.company_name || 'AnyVision Media',
  region: fields.region || 'South Africa',
  language: fields.language || 'en',
  timezone: fields.timezone || 'Africa/Johannesburg',
  isActive: fields.is_active !== false,
  autoReply: fields.auto_reply !== false,
  isOnline: fields.is_online === true,
  lastSeen: fields.last_seen || null,
  onlineThresholdMinutes: parseInt(fields.online_threshold_minutes || '5'),
  botType: fields.bot_type || 'business',
  customSystemPrompt: fields.custom_system_prompt || '',
  aiModel: fields.openrouter_model || fields.ai_model || 'anthropic/claude-sonnet-4-20250514',
  aiTemperature: parseFloat(fields.ai_temperature || '0.7'),
  maxResponseLength: parseInt(fields.max_response_length || '500'),
  airtableBaseId: fields.airtable_base_id || 'appzcZpiIZ6QPtJXT',
  whatsappPhoneNumberId: message.phoneNumberId,
  // New fields for business hours & agent toggle
  businessHoursStart: fields.business_hours_start || '08:00',
  businessHoursEnd: fields.business_hours_end || '17:00',
  agentPersonalNumber: (fields.agent_personal_number || '').replace(/\D/g, ''),
  manualOverride: fields.manual_override || null,
  manualOverrideExpiry: fields.manual_override_expiry || null,
};

// Build conversation ID for history lookup
const conversationId = `${agent.id}_${message.from}`;

const _out = {
  ...message,
  agent: agent,
  agentId: agent.id,
  agentName: agent.agentName,
  agentRecordId: agent.recordId,
  conversationId: conversationId,
};
return [{ json: _out }];

// Build AI context: business hours check + manual override + conversation history
const message = $('Merge Agent Data').first().json;
const historyRaw = $input.all();
const agent = message.agent;

// --- DETERMINE IF AI SHOULD RESPOND ---
let shouldBlock = false;
let blockReason = null;

// 1. Check manual override first (takes priority)
if (agent.manualOverride) {
  // Check if override has expired
  const expiry = agent.manualOverrideExpiry ? new Date(agent.manualOverrideExpiry).getTime() : 0;
  const overrideValid = !agent.manualOverrideExpiry || expiry > Date.now();

  if (overrideValid) {
    if (agent.manualOverride === 'online') {
      // Agent manually set ONLINE — block AI
      shouldBlock = true;
      blockReason = 'agent_online_manual';
    }
    // If manual override is 'offline', AI takes over (shouldBlock stays false)
  }
  // If expired, fall through to business hours check
}

// 2. If no valid manual override, check business hours
if (!shouldBlock && !blockReason) {
  const tz = agent.timezone || 'Africa/Johannesburg';
  const now = new Date();

  // Get current time in agent's timezone
  const timeStr = now.toLocaleTimeString('en-GB', { timeZone: tz, hour12: false, hour: '2-digit', minute: '2-digit' });
  const [nowH, nowM] = timeStr.split(':').map(Number);
  const nowMinutes = nowH * 60 + nowM;

  const [startH, startM] = (agent.businessHoursStart || '08:00').split(':').map(Number);
  const startMinutes = startH * 60 + startM;

  const [endH, endM] = (agent.businessHoursEnd || '17:00').split(':').map(Number);
  const endMinutes = endH * 60 + endM;

  // Check if current time is within business hours
  const withinBusinessHours = nowMinutes >= startMinutes && nowMinutes < endMinutes;

  // Also check day of week (Mon-Fri = business days, Sat-Sun = AI takes over)
  const dayStr = now.toLocaleDateString('en-GB', { timeZone: tz, weekday: 'short' });
  const isWeekday = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri'].includes(dayStr);

  if (withinBusinessHours && isWeekday) {
    // During business hours on weekdays — agent is "available", block AI
    shouldBlock = true;
    blockReason = 'business_hours';
  }
  // Outside business hours or weekends — AI takes over
}

// 3. Rate limiting: count inbound messages in last 5 minutes
const records = historyRaw
  .map(item => item.json)
  .filter(r => r && (r.fields || r.message_body))
  .reverse();

const fiveMinAgo = Date.now() - 300000;
const recentInbound = records.filter(r => {
  const f = r.fields || r;
  return f.direction === 'inbound' && new Date(f.timestamp).getTime() > fiveMinAgo;
}).length;

if (recentInbound > 10 && !shouldBlock) {
  shouldBlock = true;
  blockReason = 'rate_limited';
}

// --- BUILD CONVERSATION HISTORY ---
const conversationMessages = [];

for (const record of records) {
  const f = record.fields || record;
  const body = f.message_body || '';
  if (!body) continue;

  if (f.direction === 'inbound') {
    conversationMessages.push({ role: 'user', content: body });
  } else if (f.direction === 'outbound') {
    conversationMessages.push({ role: 'assistant', content: body });
  }
}

// Remove the last inbound message from history (it's the current one)
if (conversationMessages.length > 0 &&
    conversationMessages[conversationMessages.length - 1].role === 'user') {
  conversationMessages.pop();
}

const _out = {
  ...message,
  shouldBlock: shouldBlock,
  blockReason: blockReason,
  sessionExpired: false,
  conversationHistory: conversationMessages,
  historyCount: conversationMessages.length,
  processingStartTime: Date.now(),
};
return [{ json: _out }];

// Parse AI response - handles both JSON and plain text
const input = $input.first().json;

// If AI failed, fallback already prepared the response
if (input.aiFailed) {
  return input;
}

const message = $('Build AI Context').first().json;
const aiResponse = input;
const botType = message.agent.botType;

const content = aiResponse.choices?.[0]?.message?.content || '';

// For business bots, AI responds in plain text (no Airtable ops)
if (botType === 'business' || botType === 'custom') {
  let response = content.trim();
  const maxLen = message.agent.maxResponseLength || 500;
  if (response.length > maxLen) response = response.substring(0, maxLen - 3) + '...';

  const _out = {
    ...message,
    intent: 'general',
    action: 'respond',
    aiResponse: response,
    airtableOperation: { needed: false },
    confidence: 0.9,
  };
  return [{ json: _out }];
}

// For real_estate bots, try to parse JSON
let parsed = {
  intent: 'general',
  action: 'respond',
  response: content.trim(),
  airtable_operation: { needed: false },
  confidence: 0.5,
};

try {
  const jsonMatch = content.match(/```(?:json)?\\s*([\\s\\S]*?)\\s*```/);
  const jsonString = jsonMatch ? jsonMatch[1] : content;
  const aiParsed = JSON.parse(jsonString.trim());

  parsed = {
    intent: aiParsed.intent || 'general',
    action: aiParsed.action || 'respond',
    response: aiParsed.response || content.trim(),
    airtable_operation: {
      needed: aiParsed.airtable_operation?.needed || false,
      operation: aiParsed.airtable_operation?.operation || 'read',
      table: aiParsed.airtable_operation?.table || 'properties',
      filter: aiParsed.airtable_operation?.filter || '',
      data: aiParsed.airtable_operation?.data || {},
    },
    confidence: aiParsed.confidence || 0.5,
  };
} catch (e) {
  // Not JSON - use plain text response
}

// Security: validate operations
const op = parsed.airtable_operation;
if (op.needed) {
  const allowedOps = ['create', 'read'];
  const allowedTables = ['properties', 'leads', 'appointments', 'tasks', 'notes'];
  if (!allowedOps.includes(op.operation)) op.needed = false;
  if (!allowedTables.includes(op.table)) op.needed = false;
  // Scope filter to agent
  if (op.operation === 'read' && op.filter && !op.filter.includes(message.agentId)) {
    op.filter = `AND({agent_id} = '${message.agentId}', ${op.filter})`;
  }
  if (op.operation === 'create' && op.data) {
    op.data.agent_id = message.agentId;
  }
}

let response = parsed.response;
const maxLen = message.agent.maxResponseLength || 500;
if (response.length > maxLen) response = response.substring(0, maxLen - 3) + '...';

const _out = {
  ...message,
  intent: parsed.intent,
  action: parsed.action,
  aiResponse: response,
  airtableOperation: op,
  confidence: parsed.confidence,
};
return [{ json: _out }];

// Prepare final response for WhatsApp delivery
const message = $('Parse AI Decision').first().json;
let finalResponse = message.aiResponse || 'Thank you for your message.';

// Strip markdown (WhatsApp doesn't render it)
function stripMarkdown(text) {
  return text
    .replace(/```[\\s\\S]*?```/g, '')           // remove code blocks
    .replace(/`([^`]+)`/g, '$1')                // inline code -> plain
    .replace(/^#{1,6}\\s+(.+)$/gm, '$1')       // headers -> plain text
    .replace(/\\*\\*(.+?)\\*\\*/g, '*$1*')     // **bold** -> *bold* (WA format)
    .replace(/__(.+?)__/g, '*$1*')              // __bold__ -> *bold*
    .replace(/\\[([^\\]]+)\\]\\(([^)]+)\\)/g, '$1: $2') // [text](url) -> text: url
    .replace(/^[\\s]*[-*+]\\s+/gm, '- ')       // normalize bullets
    .replace(/^>\\s?/gm, '')                    // remove blockquotes
    .replace(/\\n{3,}/g, '\\n\\n')              // collapse excess newlines
    .trim();
}
finalResponse = stripMarkdown(finalResponse);

// Calculate processing time
const processingTime = Date.now() - message.processingStartTime;

const _out = {
  messageId: message.messageId,
  to: message.from,
  phoneNumberId: message.agent.whatsappPhoneNumberId,
  body: finalResponse,
  agentId: message.agentId,
  agentName: message.agentName,
  conversationId: message.conversationId,
  processingTimeMs: processingTime,
  processingTimeSec: (processingTime / 1000).toFixed(2),
  timestamp: new Date().toISOString(),
  context: {
    intent: message.intent,
    action: message.action,
    confidence: message.confidence,
    historyCount: message.historyCount,
  },
};
return [{ json: _out }];

const error = $input.first().json;
const _out = {
  timestamp: new Date().toISOString(),
  errorType: 'workflow_error',
  errorMessage: (error.message || error.error || 'Unknown error').substring(0, 500),
  nodeName: error.node?.name || 'Unknown',
  nodeType: error.node?.type || 'Unknown',
  executionId: $execution.id,
  workflowName: $workflow.name,
};
return [{ json: _out }];

const data = $input.first().json;
if (!data.agent_id) throw new Error('Missing agent_id');
if (!data.status || !['online', 'offline'].includes(data.status)) {
  throw new Error('Status must be online or offline');
}
const _out = {
  agentId: data.agent_id,
  status: data.status,
  timestamp: new Date().toISOString(),
};
return [{ json: _out }];

// Check if message is an opt-out keyword
const message = $('Parse Message').first().json;
const body = (message.body || '').trim().toUpperCase();
const optOutKeywords = ["STOP", "UNSUBSCRIBE", "OPT OUT", "CANCEL", "QUIT", "END"];
const isOptOut = optOutKeywords.some(kw => body === kw || body.startsWith(kw + ' '));

return {
  ...message,
  isOptOut: isOptOut,
};

